async (params, browser) => {
  // Open Booking.com deals page
  await browser.open('https://www.booking.com/dealspage.html')

  // Wait for deals to load
  await browser.waitForSelector('[data-testid=\'property-card\'], .bui-card, .deal-card, [data-testid=\'deal-card\'], .sr_property_block', 15000)

  // Let deals page fully render
  await browser.wait(3000)

  // Scroll to load more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Scroll for even more deals
  await browser.scroll({ direction: 'down', amount: 1200 })

  await browser.wait(2000)

  // Extract current deals
  const deals_data = await browser.evaluate(`const deals = []; const dealCards = document.querySelectorAll('[data-testid="property-card"], .bui-card, .deal-card, [data-testid="deal-card"], .sr_property_block, [data-testid="recommendation-item"]'); dealCards.forEach(function(el, idx) { if (idx >= 20) return; const nameEl = el.querySelector('[data-testid="title"], .bui-card__title, .sr-hotel__name, a[data-testid="title-link"] div, h3'); const linkEl = el.querySelector('a[data-testid="title-link"], a.bui-card__header-link, a.hotel_name_link, a[href*="/hotel/"]'); const priceEl = el.querySelector('[data-testid="price-and-discounted-price"], .bui-price-display__value, .prco-valign-middle-helper'); const originalPriceEl = el.querySelector('.bui-price-display__original, .prco-text-nowrap-helper del, [data-testid="price-original"]'); const discountEl = el.querySelector('[data-testid="price-discount"], .bui-badge, .deal-badge, [class*="discount"]'); const ratingEl = el.querySelector('[data-testid="review-score"] div:first-child, .bui-review-score__badge'); const ratingTextEl = el.querySelector('[data-testid="review-score"] div:nth-child(2) div:first-child, .bui-review-score__text'); const locationEl = el.querySelector('[data-testid="address"], .sr_card_address_line, [data-testid="distance"]'); const imgEl = el.querySelector('img[data-testid="image"], img.hotel_image, img[loading]'); const dealTypeEl = el.querySelector('.deal-type, [data-testid="deal-type"], .bui-badge--constructive, [class*="genius"]'); const url = linkEl ? (linkEl.href.startsWith('http') ? linkEl.href : 'https://www.booking.com' + linkEl.getAttribute('href')) : ''; const name = nameEl ? nameEl.textContent.trim() : ''; if (name) { deals.push({ name: name.substring(0, 200), location: locationEl ? locationEl.textContent.trim() : '', deal_price: priceEl ? priceEl.textContent.trim() : '', original_price: originalPriceEl ? originalPriceEl.textContent.trim() : '', discount: discountEl ? discountEl.textContent.trim() : '', deal_type: dealTypeEl ? dealTypeEl.textContent.trim() : '', rating_score: ratingEl ? ratingEl.textContent.trim() : '', rating_text: ratingTextEl ? ratingTextEl.textContent.trim() : '', image: imgEl ? imgEl.getAttribute('src') : '', url: url }); } }); return { deal_count: deals.length, deals: deals, scraped_at: new Date().toISOString() }`)

  return deals_data
}
